import React, { useState, useEffect } from 'react';
import { CSSTransition, TransitionGroup } from 'react-transition-group';
import styled from 'styled-components';
import { navDelay, loaderDelay } from '@utils';
import { usePrefersReducedMotion } from '@hooks';

const StyledHeroSection = styled.section`
  ${({ theme }) => theme.mixins.flexCenter};
  flex-direction: column;
  align-items: flex-start;
  min-height: 100vh;
  padding-top: calc(var(--nav-height) + 80px);

  @media (max-height: 700px) and (min-width: 700px), (max-width: 360px) {
    height: auto;
  }

  h1 {
    margin: 0 0 30px 4px;
    color: var(--green);
    font-family: var(--font-mono);
    font-size: clamp(var(--fz-sm), 5vw, var(--fz-md));
    font-weight: 400;

    @media (max-width: 480px) {
      margin: 0 0 20px 2px;
    }
  }

  .big-heading {
    margin: 0;
    font-size: clamp(40px, 8vw, 80px);
    line-height: 1.1;
  }

  .medium-heading {
    margin: 10px 0 0 0;
    color: var(--slate);
    font-size: clamp(18px, 3.5vw, 34px);
    line-height: 1.1;
  }

  p {
    margin: 12px 0 0;
    max-width: 540px;
    line-height: 1.5;
  }

  .email-link {
    ${({ theme }) => theme.mixins.bigButton};
    margin-top: 24px;
    position: relative;
    z-index: 1;
  }
`;

const Hero = () => {
  const [isMounted, setIsMounted] = useState(false);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) return;
    const timeout = setTimeout(() => setIsMounted(true), navDelay);
    return () => clearTimeout(timeout);
  }, [prefersReducedMotion]);

  const one = <h1>Hi, my name is</h1>;
  const two = <h2 className="big-heading">Susitra Gnanasambhandam</h2>;
  const three = (
    <h3 className="medium-heading">Healthcare Informatics &amp; Implementation Professional</h3>
  );

  const four = (
    <>
      <p>
        FHIR &middot; EHR &middot; Clinical Analytics &middot; Health IT &middot; Harvard Research
      </p>
    </>
  );

  const five = (
    <a className="email-link" href="mailto:susitragnanasambhandam@gmail.com">
      Say hi
    </a>
  );

  const items = [one, two, three, four, five];

  return (
    <StyledHeroSection>
      {prefersReducedMotion ? (
        <>
          {items.map((item, i) => (
            <div key={i}>{item}</div>
          ))}
        </>
      ) : (
        <TransitionGroup component={null}>
          {isMounted &&
            items.map((item, i) => (
              <CSSTransition key={i} classNames="fadeup" timeout={loaderDelay}>
                <div style={{ transitionDelay: `${i + 1}00ms` }}>{item}</div>
              </CSSTransition>
            ))}
        </TransitionGroup>
      )}
    </StyledHeroSection>
  );
};

export default Hero;